    X    ,
    A    ,
    SLEEP
);// Module ports
    output X    ;
    input  A    ;
    input  SLEEP;

    // Local signals
    wire obf_sleepn;

    //  Name  Output  Other arguments
    not not0 (obf_sleepn, SLEEP          );
    and and0 (X     , A, obf_sleepn      );

endmodule
